## SW Kayıt
```javascript
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('/sw.js', {scope: '/'})
    .then(reg => {
      reg.addEventListener('updatefound', () => {
        // Yeni versiyon bulundu
      });
    });
}
```

## SW Lifecycle
```javascript
const CACHE = 'v1';
self.addEventListener('install', e => {
  e.waitUntil(caches.open(CACHE).then(c => c.addAll(['/','app.js','style.css'])));
});
self.addEventListener('activate', e => {
  e.waitUntil(caches.keys().then(keys =>
    Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k)))));
});
```

## Cache First
```javascript
self.addEventListener('fetch', e => {
  e.respondWith(
    caches.match(e.request).then(cached =>
      cached || fetch(e.request).then(res => {
        const clone = res.clone();
        caches.open(CACHE).then(c => c.put(e.request, clone));
        return res;
      })
    )
  );
});
```

## Network First
```javascript
self.addEventListener('fetch', e => {
  e.respondWith(
    fetch(e.request)
      .then(res => { /* cache'e yaz */ return res; })
      .catch(() => caches.match(e.request))
  );
});
```
API çağrıları ve dinamik içerik için ideal.

## Stale-While-Revalidate
```javascript
self.addEventListener('fetch', e => {
  e.respondWith(
    caches.open(CACHE).then(cache =>
      cache.match(e.request).then(cached => {
        const fresh = fetch(e.request).then(res => { cache.put(e.request, res.clone()); return res; });
        return cached || fresh;
      })
    )
  );
});
```

## Push Subscription
```javascript
async function subscribePush() {
  const permission = await Notification.requestPermission();
  if (permission !== 'granted') return;
  const sub = await reg.pushManager.subscribe({
    userVisibleOnly: true,
    applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC)
  });
  await fetch('/api/subscribe', {method:'POST', body: JSON.stringify(sub)});
}
```

## Push Handler
```javascript
self.addEventListener('push', e => {
  const data = e.data.json();
  e.waitUntil(
    self.registration.showNotification(data.title, {
      body: data.body,
      icon: '/icon-192.png',
      badge: '/badge.png',
      data: { url: data.url }
    })
  );
});
```

## Lazy Loading
```javascript
// Dynamic import (React)
const Dashboard = lazy(() => import('./Dashboard'));
// Görsel lazy load
<img loading="lazy" src="photo.jpg" alt="...">
// Intersection Observer ile özel
const obs = new IntersectionObserver(entries => {
  entries.forEach(e => { if(e.isIntersecting) loadImage(e.target); });
});
```

## Workbox
```javascript
import {precacheAndRoute, registerRoute, CacheFirst, NetworkFirst} from 'workbox-*';
precacheAndRoute(self.__WB_MANIFEST);
registerRoute(({url}) => url.pathname.startsWith('/api'), new NetworkFirst());
registerRoute(({request}) => request.destination === 'image', new CacheFirst());
```

## Background Sync
```javascript
// Çevrimdışıyken kaydet
navigator.serviceWorker.ready.then(reg =>
  reg.sync.register('form-submit')
);
// SW'de
self.addEventListener('sync', e => {
  if (e.tag === 'form-submit')
    e.waitUntil(sendPendingForms());
});
```
